1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge case: empty
6	  it("empty item list yields premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (no modifiers, with fee)
15	  it.todo("single sword for newcomer first contract: 100 base + 10 first + 5 fee = 115 G");
16	  it.todo("single amulet for newcomer first contract: 60 base + 6 first + 5 fee = 71 G");
17	  it.todo("single staff for newcomer first contract: 80 base + 8 first + 5 fee = 93 G");
18	  it.todo("single potion for newcomer first contract: 40 base + 4 first + 5 fee = 49 G");
19	
20	  // Components
21	  it.todo("2 runes: 50 G base premium (+10% first +fee) = 60 G");
22	  it.todo("3 runes: 60 G base premium (block applies) (+10% first +fee) = 71 G");
23	  it.todo("4 runes: 100 G base premium (no block - block requires exactly 3) (+10% +fee) = 115 G");
24	  it.todo("7 runes: 175 G base premium (+10% +fee) = 198 G (rounded up from 197.5)");
25	
26	  // Alike component clarification
27	  it.todo("2 runes + 1 moonstone: 75 G base (no block: different types)");
28	  it.todo("3 runes + 3 moonstones: 120 G base (two separate blocks)");
29	
30	  // Premium modifiers
31	  it.todo("newcomer cursed sword (steel, enchantment 3): 165 G (100 base + 50 curse + 10 first + 5 fee)");
32	  it.todo("sword with exactly enchantment 5: high-enchantment surcharge applies");
33	  it.todo("sword with enchantment 4: no high-enchantment surcharge");
34	  it.todo("sword cursed and enchantment 5: both surcharges apply");
35	  it.todo("customer with exactly 2 years: loyalty discount applies");
36	
37	  // Modifier scope on multi-item policies
38	  it.todo("policy with cursed sword and plain amulet: cursed surcharge only on cursed item");
39	
40	  // Integration: long-standing customer's second contract
41	  it.todo("3yr customer 2nd contract, cursed sword enchantment 7: 160 G");
42	
43	  // Rounding
44	  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G");
45	
46	  // Claim - simple
47	  it.todo("standard sword (steel, enchantment 3) damage 500 G: payout 400 G");
48	  it.todo("rune damage 200 G: payout 100 G (no special clauses)");
49	
50	  // Claim with high enchantment
51	  it.todo("dragon-material sword enchantment 8 damage 1000 G: payout 400 G (high-enchant then deductible)");
