53	  it.todo("dragon-material sword enchantment 5 damage 800 G: payout 700 G (dragon full, then deductible)");
54	  it.todo("steel sword enchantment 9 damage 1000 G: payout 400 G (50% then deductible)");
55	
56	  // Deductible per damage event
57	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G");
58	
59	  // Multiple items of same type
60	  it.todo("two swords: insurance sum 2000 G, cap 4000 G");
61	  it.todo("two swords both damaged: each entry treated as separate damage with own deductible");
62	  it.todo("damages array has more entries of a type than policy covers: CLI exits non-zero");
63	
64	  // Cap
65	  it.todo("policy: sword + amulet: insurance sum 1600 G, cap 3200 G");
66	  it.todo("cursed sword cap based on unmodified insurance value: cap 2000 G");
67	  it.todo("policy sword + 3 runes block: insurance sum 1750 G");
